async function seedTechnicalQuestions() {
  console.log('🚀 Starting technical questions seeding...');
  console.log(`📊 Total job categories: ${Object.keys(CATEGORY_QUESTIONS).length}`);
  console.log(`📊 Total positions: ${JOB_POSITIONS.length}`);
  
  let totalCreated = 0;
  let positionsProcessed = 0;
  
  for (const position of JOB_POSITIONS) {
    const categoryQuestions = CATEGORY_QUESTIONS[position.category];
    
    if (!categoryQuestions || categoryQuestions.length === 0) {
      console.log(`⚠️ No questions for category: ${position.category}`);
      continue;
    }
    
    // Check existing questions
    const existingCount = await prisma.technicalQuestion.count({
      where: { jobPositionId: position.id }
    });
    
    if (existingCount >= 9) {
      console.log(`  ✅ ${position.title} already has ${existingCount} questions`);
      positionsProcessed++;
      totalCreated += existingCount;
      continue;
    }
    
    const toCreate = Math.min(9, categoryQuestions.length) - existingCount;
    
    if (toCreate <= 0) {
      positionsProcessed++;
      continue;
    }
    
    // Select questions for this position (cycling through available questions)
    const offset = positionsProcessed % categoryQuestions.length;
    
    for (let i = 0; i < toCreate; i++) {
      const qIndex = (offset + existingCount + i) % categoryQuestions.length;
      const q = categoryQuestions[qIndex];
      const questionNumber = existingCount + i + 1;
      
      try {
        await prisma.technicalQuestion.create({
          data: {
            jobPositionId: position.id,
            questionNumber: questionNumber,
            questionText: q.questionText,
            questionTextEn: q.questionTextEn,
            optionA: q.optionA,
            optionB: q.optionB,
            optionC: q.optionC,
            optionD: q.optionD,
            optionAEn: q.optionAEn,
            optionBEn: q.optionBEn,
            optionCEn: q.optionCEn,
            optionDEn: q.optionDEn,
            correctAnswer: q.correctAnswer,
            difficulty: q.difficulty as TechnicalDifficulty,
            category: q.category,
            categoryEn: q.categoryEn,
            weight: q.difficulty === 'EASY' ? 1 : q.difficulty === 'MEDIUM' ? 2 : 3,
          },
        });
        totalCreated++;
      } catch (err) {
        // Skip duplicates
      }
    }
    
    positionsProcessed++;
    if (positionsProcessed % 20 === 0) {
      console.log(`📈 Progress: ${positionsProcessed}/${JOB_POSITIONS.length} positions, ${totalCreated} questions created`);
    }
  }
  
  console.log('\n' + '='.repeat(50));
  console.log('📊 SEEDING COMPLETE');
  console.log(`✅ Total questions created: ${totalCreated}`);
  console.log(`📦 Positions processed: ${positionsProcessed}`);
  
  // Show total
  const totalQuestions = await prisma.technicalQuestion.count();
  console.log(`🎯 Total questions in database: ${totalQuestions}`);
  
  // Show distribution
  const stats = await prisma.technicalQuestion.groupBy({
    by: ['difficulty'],
    _count: true,
  });
  
  console.log('\n📊 Distribution by difficulty:');
  stats.forEach(s => console.log(`  ${s.difficulty}: ${s._count}`));
}

seedTechnicalQuestions()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
